"const fs = require('fs');

function convertFile(filename) {
  if (!fs.existsSync(filename)) return;
  let content = fs.readFileSync(filename, 'utf8');

  // Replace literal '\n' string with actual newline
  content = content.split('\\n').join('\n');
  content = content.split('\\"').join('"');
  content = content.split('\\\\').join('\\');

  // Remove leading and trailing double quotes if they wrap the entire file
  content = content.trim();
  if (content.startsWith('"') && content.endsWith('"')) {
    content = content.slice(1, -1);
  }

  fs.writeFileSync(filename + '.clean.txt', content, 'utf8');
  console.log(`Cleaned ${filename} -> ${filename}.clean.txt`);
}

