"const { createClient } = require('@supabase/supabase-js');

const supabaseUrl = 'https://jssoyjwjqykcuovdydtz.supabase.co';
const supabaseKey = 'sb_publishable_RztM_8dNswdYyCo_3ZTFyA_94mkh6xz';
const supabase = createClient(supabaseUrl, supabaseKey);

async function testUpdateAdmin() {
  console.log('1. Signing in as system admin...');
  const { data: authData, error: authError } = await supabase.auth.signInWithPassword({
    email: 'admin@el-town.jp',
    password: 'eltown-admin'
  });

  if (authError) {
    console.error('❌ Sign in failed:', authError);
    return;
  }
  console.log('✅ Sign in successful! User ID:', authData.user.id);

  console.log('2. Updating stripe_account_id on neighborhood ID 1 (希望ヶ丘)...');
  const { data, error } = await supabase
    .from('neighborhoods')
    .update({ stripe_account_id: 'acct_test_admin_success' })
    .eq('id', 1)
    .select();

  if (error) {
    console.error('❌ Update failed with error:', error);
  } else {
    console.log('✅ Update succeeded! Returned data:', data);
  }

  // 3. 元に戻す (テスト完了のため)
  console.log('3. Restoring stripe_account_id to null...');
  const { error: restoreError } = await supabase
    .from('neighborhoods')
    .update({ stripe_account_id: null })
    .eq('id', 1);

